import React, { useEffect, useState, useMemo } from 'https://esm.sh/react@18.2.0';
import ReactDOM from 'https://esm.sh/react-dom@18.2.0/client';

function IZOHorizontalBarChart(props) {
  const [isLoaded, setIsLoaded] = useState(false);
  const [tooltip, setTooltip] = useState({ show: false, x: 0, y: 0, name: '', count: 0 });

  useEffect(() => {
    const styleId = 'izo-inner-scroll-fix';
    if (!document.getElementById(styleId)) {
      const style = document.createElement('style');
      style.id = styleId;
      style.innerHTML = `
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');
        html, body, #root { 
          height: 100% !important; 
          margin: 0; padding: 0; 
          overflow: hidden !important; 
          font-family: 'Inter', sans-serif; 
          background: white;
        }
        .inner-scroll::-webkit-scrollbar { width: 4px; }
        .inner-scroll::-webkit-scrollbar-track { background: transparent; }
        .inner-scroll::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 10px; }
        .izo-tooltip {
          position: fixed;
          pointer-events: none;
          background: #1f2937;
          color: white;
          padding: 8px 12px;
          border-radius: 6px;
          font-size: 12px;
          z-index: 9999;
          box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1);
          transform: translate(-50%, -120%);
          transition: opacity 0.1s ease;
          white-space: nowrap;
        }
      `;
      document.head.appendChild(style);
    }

    if (!document.getElementById('tailwind-v4')) {
      const script = document.createElement('script');
      script.id = 'tailwind-v4';
      script.src = 'https://cdn.jsdelivr.net/npm/@tailwindcss/browser@4';
      script.onload = () => setIsLoaded(true);
      document.head.appendChild(script);
    } else {
      setIsLoaded(true);
    }
  }, []);

  const resolved = useMemo(() => {
    const raw = props.data || {};
    const list = raw.data || [
      { name: "RWE", count: 186 },
      { name: "Safety", count: 305 },
      { name: "MOA", count: 237 },
      { name: "Clinical Trials", count: 73 },
      { name: "Efficacy", count: 209 },
      { name: "Adherence", count: 110 },
      { name: "Digital Health", count: 95 }
    ];
    const max = list.length > 0 ? Math.max(...list.map(i => i.count)) : 0;
    const defaultColors = ["#0B5E2A", "#2E8B57", "#4FA66A", "#A3DEC0", "#CEF1E0"];
    const colors = (raw.colors && Array.isArray(raw.colors)) ? raw.colors : defaultColors;

    return { title: raw.title || "Content Affinity", subtitle: raw.subtitle || "High-impact topics", items: list, maxValue: max, colors: colors };
  }, [props.data]);

  const handleShowTooltip = (e, item) => {
    setTooltip({ show: true, x: e.clientX, y: e.clientY, name: item.name, count: item.count });
  };
  const handleHideTooltip = () => setTooltip(prev => ({ ...prev, show: false }));

  if (!isLoaded) return null;
  const { title, subtitle, items, maxValue, colors } = resolved;

  return React.createElement(
    'div',
    { className: "flex flex-col h-full w-full p-8 bg-white overflow-hidden" },

    tooltip.show && React.createElement(
      'div',
      { className: "izo-tooltip", style: { left: tooltip.x, top: tooltip.y } },
      React.createElement('div', { className: "font-semibold" }, tooltip.name)
    ),

    React.createElement('div', { className: "mb-6 shrink-0" },
      React.createElement('h3', { className: "text-[16px] font-medium text-[#252726] mb-1" }, title),
      React.createElement('p', { className: "text-[14px] font-regular text-[#252726] opacity-80" }, subtitle)
    ),

    React.createElement('div', { className: "inner-scroll flex-1 flex flex-col gap-4 overflow-y-auto min-h-0 pr-2" },
      items.map((item, index) => {
        const percentage = maxValue > 0 ? (item.count / maxValue) * 100 : 0;

        return React.createElement('div', { key: index, className: "group flex items-center gap-0 cursor-pointer shrink-0", onClick: () => props.updateData({ selected: item.name }) },

          // Tooltip on LABEL
          React.createElement('div', { 
            className: "w-28 text-[14px] font-bold text-[#737373] transition-colors group-hover:text-[#252726] truncate pr-2",
            onMouseEnter: (e) => handleShowTooltip(e, item),
            onMouseMove: (e) => handleShowTooltip(e, item),
            onMouseLeave: handleHideTooltip
          }, item.name),

          // Tooltip on BAR
          React.createElement('div', { 
            className: "flex-1 h-3.5 relative",
            onMouseEnter: (e) => handleShowTooltip(e, item),
            onMouseMove: (e) => handleShowTooltip(e, item),
            onMouseLeave: handleHideTooltip
          },
            React.createElement('div', {
              className: "h-full rounded-full transition-all duration-1000 ease-out",
              style: { width: percentage + "%", backgroundColor: colors[index % colors.length] }
            })
          ),

          // NO Tooltip on COUNT
          React.createElement('span', { className: "text-[14px] font-medium text-[#737373] w-10 text-right tabular-nums" }, item.count)
        );
      })
    )
  );
}

const ConnectedComponent = Tooljet.connectComponent(IZOHorizontalBarChart);
if (!window.tooljetRoot) { window.tooljetRoot = ReactDOM.createRoot(document.body); }
window.tooljetRoot.render(React.createElement(ConnectedComponent));
